// RegisterIntents adds the spec-declared intent tools to the MCP server.
// This is called from RegisterTools when MCP.Intents is non-empty.
func RegisterIntents(s *server.MCPServer) {
	s.AddTool(
		mcplib.NewTool("add_item_to_list",
			mcplib.WithDescription("Add a named item to a shopping list with optional quantity and notes"),
			mcplib.WithString("list_name", mcplib.Description("")),
			mcplib.WithString("item_name", mcplib.Description("")),
			mcplib.WithString("quantity", mcplib.Description("")),
		),
		handleAddItemToList,
	)
	s.AddTool(
		mcplib.NewTool("search_items",
			mcplib.WithDescription("Search for items by name across all shopping lists"),
			mcplib.WithString("query", mcplib.Description("")),
		),
		handleSearchItems,
	)
	s.AddTool(
		mcplib.NewTool("build_shopping_list_from_meal_plan",
			mcplib.WithDescription("Add all recipe ingredients from this week's meal plan to a shopping list"),
			mcplib.WithString("list_name", mcplib.Description("")),
		),
		handleBuildShoppingListFromMealPlan,
	)
	s.AddTool(
		mcplib.NewTool("get_meal_plan_grid",
			mcplib.WithDescription("Get the current week's meal plan as a Mon-Sun grid with meal labels"),
		),
		handleGetMealPlanGrid,
	)
	s.AddTool(
		mcplib.NewTool("get_list_by_store",
			mcplib.WithDescription("Get a shopping list organized by store and aisle order for efficient multi-store shopping"),
			mcplib.WithString("list_name", mcplib.Description("")),
		),
		handleGetListByStore,
	)
}

